import{c as t,Q as a,j as n,m as s}from"./chunks/framework.BXc4yaFE.js";const p=JSON.parse('{"title":"The Decoder — 2026-05-25","description":"","frontmatter":{"title":"The Decoder — 2026-05-25","date":"2026-05-25T00:00:00.000Z","source":"The Decoder","type":"ai-news"},"headers":[],"relativePath":"research/ai-news/2026-05/2026-05-25-the-decoder.md","filePath":"research/ai-news/2026-05/2026-05-25-the-decoder.md","lastUpdated":1779894392000}'),o={name:"research/ai-news/2026-05/2026-05-25-the-decoder.md"};function r(i,e,l,h,d,c){return a(),n("div",null,[...e[0]||(e[0]=[s('<h1 id="🔓-the-decoder-—-2026-05-25" tabindex="-1">🔓 The Decoder — 2026-05-25 <a class="header-anchor" href="#🔓-the-decoder-—-2026-05-25" aria-label="Permalink to &quot;🔓 The Decoder — 2026-05-25&quot;">​</a></h1><blockquote><p>企業 AI 開發與模型應用日報，涵蓋 AI 社會影響（英語媒體） 來源：<a href="https://the-decoder.com/feed/" target="_blank" rel="noreferrer">The Decoder</a></p></blockquote><hr><h2 id="bytedance-study-finds-that-asking-lmms-questions-beats-making-it-transcribe-text-for-long-document-training" tabindex="-1"><a href="https://the-decoder.com/bytedance-study-finds-that-asking-lmms-questions-beats-making-it-transcribe-text-for-long-document-training/" target="_blank" rel="noreferrer">ByteDance study finds that asking LMMs questions beats making it transcribe text for long document training</a> <a class="header-anchor" href="#bytedance-study-finds-that-asking-lmms-questions-beats-making-it-transcribe-text-for-long-document-training" aria-label="Permalink to &quot;[ByteDance study finds that asking LMMs questions beats making it transcribe text for long document training](https://the-decoder.com/bytedance-study-finds-that-asking-lmms-questions-beats-making-it-transcribe-text-for-long-document-training/)&quot;">​</a></h2><p><em>🔓 The Decoder | 2026-05-24</em></p><p>ByteDance Seed shows that a 7B model can answer questions on long, image-heavy documents more reliably than much larger models, even when documents are four times longer than anything it saw during training. Instead of transcribing pages, the model learns by answering questions and finding the right passages on its own.</p><p>The article <a href="https://the-decoder.com/bytedance-study-finds-that-asking-lmms-questions-beats-making-it-transcribe-text-for-long-document-training/" target="_blank" rel="noreferrer">ByteDance study finds that asking LMMs questions beats making it transcribe text for long document training</a> appeared first on <a href="https://the-decoder.com" target="_blank" rel="noreferrer">The Decoder</a>.</p><hr><h2 id="deepmind-s-hassabis-sees-humanity-in-the-foothills-of-the-singularity-while-lecun-says-current-ai-isn-t-intelligent" tabindex="-1"><a href="https://the-decoder.com/deepminds-hassabis-sees-humanity-in-the-foothills-of-the-singularity-while-lecun-says-current-ai-isnt-intelligent/" target="_blank" rel="noreferrer">Deepmind&#39;s Hassabis sees humanity &quot;in the foothills of the singularity&quot; while LeCun says current AI isn&#39;t intelligent</a> <a class="header-anchor" href="#deepmind-s-hassabis-sees-humanity-in-the-foothills-of-the-singularity-while-lecun-says-current-ai-isn-t-intelligent" aria-label="Permalink to &quot;[Deepmind&#39;s Hassabis sees humanity &quot;in the foothills of the singularity&quot; while LeCun says current AI isn&#39;t intelligent](https://the-decoder.com/deepminds-hassabis-sees-humanity-in-the-foothills-of-the-singularity-while-lecun-says-current-ai-isnt-intelligent/)&quot;">​</a></h2><p><em>🔓 The Decoder | 2026-05-24</em></p><p>Yann LeCun says current AI systems aren&#39;t genuinely intelligent. Demis Hassabis thinks humanity is already &quot;standing in the foothills of the singularity.&quot; And Gemini co-lead Oriol Vinyals splits the difference: today&#39;s models would&#39;ve looked like AGI seven years ago, but they still can&#39;t learn from experience or produce real breakthroughs.</p><p>The article <a href="https://the-decoder.com/deepminds-hassabis-sees-humanity-in-the-foothills-of-the-singularity-while-lecun-says-current-ai-isnt-intelligent/" target="_blank" rel="noreferrer">Deepmind&#39;s Hassabis sees humanity &quot;in the foothills of the singularity&quot; while LeCun says current AI isn&#39;t intelligent</a> appeared first on <a href="https://the-decoder.com" target="_blank" rel="noreferrer">The Decoder</a>.</p><hr><h2 id="why-you-shouldn-t-leave-model-selection-on-default-in-copilot-gemini-and-other-ai-tools" tabindex="-1"><a href="https://the-decoder.com/why-you-shouldnt-leave-model-selection-on-default-in-copilot-gemini-and-other-ai-tools/" target="_blank" rel="noreferrer">Why you shouldn&#39;t leave model selection on default in Copilot, Gemini and other AI tools</a> <a class="header-anchor" href="#why-you-shouldn-t-leave-model-selection-on-default-in-copilot-gemini-and-other-ai-tools" aria-label="Permalink to &quot;[Why you shouldn&#39;t leave model selection on default in Copilot, Gemini and other AI tools](https://the-decoder.com/why-you-shouldnt-leave-model-selection-on-default-in-copilot-gemini-and-other-ai-tools/)&quot;">​</a></h2><p><em>🔓 The Decoder | 2026-05-24</em></p><p>When analyzing data, Microsoft Copilot invents country differences where none exist. Mathematician Adam Kucharski fed the tool identical datasets with different country labels, and Copilot delivered detailed stereotypes instead of accurate results. Thinking models catch the trick, but only if users know when to reach for them.</p><p>The article <a href="https://the-decoder.com/why-you-shouldnt-leave-model-selection-on-default-in-copilot-gemini-and-other-ai-tools/" target="_blank" rel="noreferrer">Why you shouldn&#39;t leave model selection on default in Copilot, Gemini and other AI tools</a> appeared first on <a href="https://the-decoder.com" target="_blank" rel="noreferrer">The Decoder</a>.</p><hr><h2 id="anthropic-may-keep-supplying-claude-to-the-nsa-despite-being-flagged-as-a-supply-chain-risk-by-the-pentagon" tabindex="-1"><a href="https://the-decoder.com/anthropic-may-keep-supplying-claude-to-the-nsa-despite-being-flagged-as-a-supply-chain-risk-by-the-pentagon/" target="_blank" rel="noreferrer">Anthropic may keep supplying Claude to the NSA despite being flagged as a supply chain risk by the Pentagon</a> <a class="header-anchor" href="#anthropic-may-keep-supplying-claude-to-the-nsa-despite-being-flagged-as-a-supply-chain-risk-by-the-pentagon" aria-label="Permalink to &quot;[Anthropic may keep supplying Claude to the NSA despite being flagged as a supply chain risk by the Pentagon](https://the-decoder.com/anthropic-may-keep-supplying-claude-to-the-nsa-despite-being-flagged-as-a-supply-chain-risk-by-the-pentagon/)&quot;">​</a></h2><p><em>🔓 The Decoder | 2026-05-24</em></p><p>Anthropic will likely keep supplying AI models to the NSA despite being labeled a &quot;supply chain risk.&quot; Intelligence agencies lack Nvidia&#39;s latest Grace Blackwell chips, and Anthropic&#39;s &quot;Mythos&quot; model reportedly runs on older hardware too. The controversial &quot;any lawful use&quot; clause that derailed earlier talks is not part of the deal.</p><p>The article <a href="https://the-decoder.com/anthropic-may-keep-supplying-claude-to-the-nsa-despite-being-flagged-as-a-supply-chain-risk-by-the-pentagon/" target="_blank" rel="noreferrer">Anthropic may keep supplying Claude to the NSA despite being flagged as a supply chain risk by the Pentagon</a> appeared first on <a href="https://the-decoder.com" target="_blank" rel="noreferrer">The Decoder</a>.</p><hr><h2 id="researchers-let-claude-code-discover-ai-scaling-algorithms-that-humans-probably-wouldn-t-have-designed" tabindex="-1"><a href="https://the-decoder.com/researchers-let-claude-code-discover-ai-scaling-algorithms-that-humans-probably-wouldnt-have-designed/" target="_blank" rel="noreferrer">Researchers let Claude Code discover AI scaling algorithms that humans probably wouldn&#39;t have designed</a> <a class="header-anchor" href="#researchers-let-claude-code-discover-ai-scaling-algorithms-that-humans-probably-wouldn-t-have-designed" aria-label="Permalink to &quot;[Researchers let Claude Code discover AI scaling algorithms that humans probably wouldn&#39;t have designed](https://the-decoder.com/researchers-let-claude-code-discover-ai-scaling-algorithms-that-humans-probably-wouldnt-have-designed/)&quot;">​</a></h2><p><em>🔓 The Decoder | 2026-05-24</em></p><p>Researchers from UMD, Google, Meta, and other institutions use AutoTTS to let a coding agent independently discover control algorithms for AI reasoning. The algorithm it found cuts compute by about 70 percent compared to standard self-consistency while matching its accuracy. The whole search cost $40 and took 160 minutes.</p><p>The article <a href="https://the-decoder.com/researchers-let-claude-code-discover-ai-scaling-algorithms-that-humans-probably-wouldnt-have-designed/" target="_blank" rel="noreferrer">Researchers let Claude Code discover AI scaling algorithms that humans probably wouldn&#39;t have designed</a> appeared first on <a href="https://the-decoder.com" target="_blank" rel="noreferrer">The Decoder</a>.</p><hr>',28)])])}const g=t(o,[["render",r]]);export{p as __pageData,g as default};
